#include<bits/stdc++.h>
using namespace std;
long long p(long long x)
{
    return(x==1?2:x*2-1);
}
long long lcm(long long x,long long y)
{
    return x/gcd(x,y)*y;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    if(n==1)
    {
        printf("0 0");
        return 0;
    }
    long long l=1,ans=0;
    for(long long i=1;i<=50;i++)
    {
        l=lcm(l,p(i));
        ans+=n/l/p(i);
        if(l>n)
        {
            break;
        }
    }
    printf("%lld %lld",(n+1)/2,ans);
    return 0;
}
